package equivalent;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static equivalent.ClonePairGenericInvocationTestSupport.*;

class ClonePair3149DifferenceFindingTest {

    private final ClonePair3149 subject = new ClonePair3149();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{new float[]{1.0f, Float.NaN}};
        InvocationOutcome method1Outcome = capture(values -> subject.method1((float[]) values[0]), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2((float[]) values[0]), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Float(1.0)",
            null,
            "java.lang.Object[][float[][1.0, NaN]]",
            "java.lang.Object[][float[][1.0, NaN]]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Float(NaN)",
            null,
            "java.lang.Object[][float[][1.0, NaN]]",
            "java.lang.Object[][float[][1.0, NaN]]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
